/**
 * Pricing Code Inventory — read-only catalogue of every file in the repo
 * that touches pricing, costing, units, conversions, inventory valuation,
 * or quote pricing. Generated by manual repo audit.
 *
 * NOTHING in this file mutates application state. It exists purely so
 * admins can review and export the inventory as PDF or JSON.
 */

export type PricingLayer =
  | "Baseline cost ingestion"
  | "Cost normalization"
  | "Unit conversion"
  | "Recipe cost calculation"
  | "Pricing model"
  | "Quote application"
  | "Guardrails / validation";

export type Recommendation = "KEEP" | "CENTRALIZE" | "EXPOSE" | "LEGACY";

export type PricingFileEntry = {
  path: string;
  does: string;
  layers: PricingLayer[];
  notes?: string;
  recommendation: Recommendation;
};

export type PricingInventorySection = {
  title: string;
  description?: string;
  entries: PricingFileEntry[];
};

