export const PRICING_INVENTORY_SQL_REFERENCE = [
  "compute_internal_estimated_cost(_kroger,_manual,_historical) → weighted estimate (40/40/20, redistributed if any source is null).",
  "propose_internal_cost_update(...) → diff vs current; auto-apply ≤5%, queue >5%; manual cost can never be overwritten by Kroger.",
  "approve_cost_update / reject_cost_update / override_cost_update → queue resolution; logs to access_audit_log; drafts a change_log_entries row when approved >5%.",
  "compute_recipe_selling_price(cost, markup_pct) → uses per-recipe markup_percentage else app_settings.markup_multiplier.",
  "trg_recipe_sync_pricing_columns → keeps calculated_cost_per_person and selling_price_per_person in sync on recipe write.",
  "recompute_quote_totals(_quote_id) → sums quote_items.total_price, applies quotes.tax_rate.",
  "apply_po_to_inventory(_po_id) → weighted-average update on PO receive + writes price_history.",
  "kroger_price_signals() view → flags inventory items as cheap/expensive/stale vs 30-day Kroger median.",
  "recipe_pricing_health_summary() → status + stale ingredient count per recipe.",
  "enforce_quote_revision_lock trigger → blocks edits within app_settings.revision_lock_days of event_date (admins bypass).",
];

